import{_ as r,o as l,c as i,ak as e}from"./chunks/framework.B_unCYUt.js";const b=JSON.parse('{"title":"程序原理","description":"","frontmatter":{},"headers":[],"relativePath":"程序原理.md","filePath":"程序原理.md","lastUpdated":1776170179000}'),n={name:"程序原理.md"};function o(t,a,s,h,d,c){return l(),i("div",null,[...a[0]||(a[0]=[e('<h1 id="程序原理" tabindex="-1">程序原理 <a class="header-anchor" href="#程序原理" aria-label="Permalink to “程序原理”">​</a></h1><blockquote><p>code, program, application,</p><p>编程技术, 概念, 思想, 范式, 技巧, 程序设计 程序执行原理 程序运行原理, 底层机制</p><p>程序设计语言</p><p>心智模型, 认知框架</p></blockquote><h2 id="心智模型" tabindex="-1">心智模型 <a class="header-anchor" href="#心智模型" aria-label="Permalink to “心智模型”">​</a></h2><ul><li>表达层</li><li>抽象层 <ul><li>抽象机制</li></ul></li><li>语义层</li><li>执行层</li><li>设计哲学</li></ul><h3 id="程序的三大本质问题" tabindex="-1">程序的三大本质问题 <a class="header-anchor" href="#程序的三大本质问题" aria-label="Permalink to “程序的三大本质问题”">​</a></h3><p>你提的三个问题可以这样统一👇</p><h4 id="_1️⃣-程序如何表达" tabindex="-1"><strong>1️⃣ 程序如何表达？</strong> <a class="header-anchor" href="#_1️⃣-程序如何表达" aria-label="Permalink to “1️⃣ 程序如何表达？”">​</a></h4><p>👉 对应：<strong>抽象层 + 表达层</strong></p><p>核心能力：</p><ul><li>数据建模（结构）</li><li>行为封装（函数）</li><li>组合（composition）</li></ul><p>👉 本质公式：<code>程序 = 数据结构 + 行为 + 组合关系</code></p><h1 id="glossary" tabindex="-1">Glossary <a class="header-anchor" href="#glossary" aria-label="Permalink to “Glossary”">​</a></h1><h2 id="items" tabindex="-1">Items <a class="header-anchor" href="#items" aria-label="Permalink to “Items”">​</a></h2><h3 id="横切关注点" tabindex="-1">横切关注点 <a class="header-anchor" href="#横切关注点" aria-label="Permalink to “横切关注点”">​</a></h3><p>cross-cutting concerns</p><blockquote><p>横切关注点, 非功能需求, 技术关注点, 基础设施关注点, 横向功能</p></blockquote><p>日志, 监控, 跟踪, 错误处理, 安全性, 缓存, 事务, 认证授权, 数据验证, 配置管理, 国际化和本地化</p><p>log, trace, metric</p><h1 id="ai总结" tabindex="-1">AI总结 <a class="header-anchor" href="#ai总结" aria-label="Permalink to “AI总结”">​</a></h1><h2 id="计算机科学-尤其是编程-有哪些第一性原理的基础知识-尤其有助于自上而下设计程序和系统-应该掌握哪些理论和技巧" tabindex="-1">计算机科学, 尤其是编程, 有哪些第一性原理的基础知识, 尤其有助于自上而下设计程序和系统, 应该掌握哪些理论和技巧 <a class="header-anchor" href="#计算机科学-尤其是编程-有哪些第一性原理的基础知识-尤其有助于自上而下设计程序和系统-应该掌握哪些理论和技巧" aria-label="Permalink to “计算机科学, 尤其是编程, 有哪些第一性原理的基础知识, 尤其有助于自上而下设计程序和系统, 应该掌握哪些理论和技巧”">​</a></h2><p>在计算机科学和编程领域，有许多基础知识和第一性原理可以帮助开发人员从高层次设计程序和系统。这些原理和理论不仅奠定了计算机科学的基础，而且在实际编程中也有广泛的应用。以下是一些关键的基础知识和技巧，特别有助于自上而下设计程序和系统。</p><h3 id="_1-计算理论" tabindex="-1">1. <strong>计算理论</strong> <a class="header-anchor" href="#_1-计算理论" aria-label="Permalink to “1. 计算理论”">​</a></h3><h4 id="图灵机和可计算性" tabindex="-1">图灵机和可计算性 <a class="header-anchor" href="#图灵机和可计算性" aria-label="Permalink to “图灵机和可计算性”">​</a></h4><ul><li><strong>概念</strong>：理解什么是计算机能够解决的问题。</li><li><strong>应用</strong>：帮助识别哪些问题可以通过算法解决，哪些问题是不可判定的。</li></ul><h4 id="复杂性理论" tabindex="-1">复杂性理论 <a class="header-anchor" href="#复杂性理论" aria-label="Permalink to “复杂性理论”">​</a></h4><ul><li><strong>概念</strong>：时间复杂度和空间复杂度，P vs NP问题。</li><li><strong>应用</strong>：帮助评估和优化算法的效率，选择适合的算法解决问题。</li></ul><h3 id="_2-算法与数据结构" tabindex="-1">2. <strong>算法与数据结构</strong> <a class="header-anchor" href="#_2-算法与数据结构" aria-label="Permalink to “2. 算法与数据结构”">​</a></h3><h4 id="基本数据结构" tabindex="-1">基本数据结构 <a class="header-anchor" href="#基本数据结构" aria-label="Permalink to “基本数据结构”">​</a></h4><ul><li><strong>概念</strong>：数组、链表、栈、队列、哈希表、树、图。</li><li><strong>应用</strong>：数据的存储和检索优化，选择合适的数据结构以提高程序性能。</li></ul><h4 id="基本算法" tabindex="-1">基本算法 <a class="header-anchor" href="#基本算法" aria-label="Permalink to “基本算法”">​</a></h4><ul><li><strong>概念</strong>：排序算法（快速排序、归并排序）、搜索算法（二分搜索、深度优先搜索、广度优先搜索）、动态规划、贪心算法。</li><li><strong>应用</strong>：解决具体问题，提高程序的计算效率。</li></ul><h3 id="_3-操作系统原理" tabindex="-1">3. <strong>操作系统原理</strong> <a class="header-anchor" href="#_3-操作系统原理" aria-label="Permalink to “3. 操作系统原理”">​</a></h3><h4 id="进程与线程管理" tabindex="-1">进程与线程管理 <a class="header-anchor" href="#进程与线程管理" aria-label="Permalink to “进程与线程管理”">​</a></h4><ul><li><strong>概念</strong>：进程、线程、并发、多线程编程。</li><li><strong>应用</strong>：设计高效的并发系统，管理资源和调度任务。</li></ul><h4 id="内存管理" tabindex="-1">内存管理 <a class="header-anchor" href="#内存管理" aria-label="Permalink to “内存管理”">​</a></h4><ul><li><strong>概念</strong>：内存分配、虚拟内存、垃圾回收。</li><li><strong>应用</strong>：优化程序的内存使用，避免内存泄漏和性能问题。</li></ul><h3 id="_4-编程范式" tabindex="-1">4. <strong>编程范式</strong> <a class="header-anchor" href="#_4-编程范式" aria-label="Permalink to “4. 编程范式”">​</a></h3><h4 id="面向对象编程-oop" tabindex="-1">面向对象编程（OOP） <a class="header-anchor" href="#面向对象编程-oop" aria-label="Permalink to “面向对象编程（OOP）”">​</a></h4><ul><li><strong>概念</strong>：封装、继承、多态、抽象。</li><li><strong>应用</strong>：设计模块化、可维护和可扩展的代码。</li></ul><h4 id="函数式编程-fp" tabindex="-1">函数式编程（FP） <a class="header-anchor" href="#函数式编程-fp" aria-label="Permalink to “函数式编程（FP）”">​</a></h4><ul><li><strong>概念</strong>：纯函数、高阶函数、不可变性、惰性计算。</li><li><strong>应用</strong>：编写简洁、可测试的代码，尤其在并发编程中减少副作用。</li></ul><h4 id="面向切面编程-aop" tabindex="-1">面向切面编程（AOP） <a class="header-anchor" href="#面向切面编程-aop" aria-label="Permalink to “面向切面编程（AOP）”">​</a></h4><ul><li><strong>概念</strong>：分离横切关注点，如日志、事务管理。</li><li><strong>应用</strong>：提高代码的模块化，减少代码重复。</li></ul><h3 id="_5-软件工程" tabindex="-1">5. <strong>软件工程</strong> <a class="header-anchor" href="#_5-软件工程" aria-label="Permalink to “5. 软件工程”">​</a></h3><h4 id="设计模式" tabindex="-1">设计模式 <a class="header-anchor" href="#设计模式" aria-label="Permalink to “设计模式”">​</a></h4><ul><li><strong>概念</strong>：常见的设计模式如单例模式、工厂模式、观察者模式、装饰器模式。</li><li><strong>应用</strong>：提供解决常见设计问题的模板，提升代码的可维护性和可读性。</li></ul><h4 id="需求分析与系统设计" tabindex="-1">需求分析与系统设计 <a class="header-anchor" href="#需求分析与系统设计" aria-label="Permalink to “需求分析与系统设计”">​</a></h4><ul><li><strong>概念</strong>：从需求到系统架构的转化，系统分层设计，模块化设计。</li><li><strong>应用</strong>：自上而下设计系统，确保满足业务需求和系统性能。</li></ul><h3 id="_6-网络和分布式系统" tabindex="-1">6. <strong>网络和分布式系统</strong> <a class="header-anchor" href="#_6-网络和分布式系统" aria-label="Permalink to “6. 网络和分布式系统”">​</a></h3><h4 id="网络基础" tabindex="-1">网络基础 <a class="header-anchor" href="#网络基础" aria-label="Permalink to “网络基础”">​</a></h4><ul><li><strong>概念</strong>：OSI模型、TCP/IP协议、HTTP协议、WebSocket。</li><li><strong>应用</strong>：设计和实现网络通信，构建可靠和高效的网络应用。</li></ul><h4 id="分布式系统" tabindex="-1">分布式系统 <a class="header-anchor" href="#分布式系统" aria-label="Permalink to “分布式系统”">​</a></h4><ul><li><strong>概念</strong>：一致性、可用性、分区容错性（CAP定理），分布式算法（如Paxos、Raft）。</li><li><strong>应用</strong>：设计高可用、可扩展的分布式系统，处理数据一致性问题。</li></ul><h3 id="_7-数据库系统" tabindex="-1">7. <strong>数据库系统</strong> <a class="header-anchor" href="#_7-数据库系统" aria-label="Permalink to “7. 数据库系统”">​</a></h3><h4 id="数据库设计" tabindex="-1">数据库设计 <a class="header-anchor" href="#数据库设计" aria-label="Permalink to “数据库设计”">​</a></h4><ul><li><strong>概念</strong>：ER模型、规范化、索引、事务管理。</li><li><strong>应用</strong>：设计高效的数据库模式，优化数据查询和存储。</li></ul><h4 id="nosql数据库" tabindex="-1">NoSQL数据库 <a class="header-anchor" href="#nosql数据库" aria-label="Permalink to “NoSQL数据库”">​</a></h4><ul><li><strong>概念</strong>：键值存储、文档数据库、列族存储、图数据库。</li><li><strong>应用</strong>：选择适合的数据库类型以满足特定应用需求。</li></ul><h3 id="_8-计算机网络" tabindex="-1">8. <strong>计算机网络</strong> <a class="header-anchor" href="#_8-计算机网络" aria-label="Permalink to “8. 计算机网络”">​</a></h3><h4 id="网络协议" tabindex="-1">网络协议 <a class="header-anchor" href="#网络协议" aria-label="Permalink to “网络协议”">​</a></h4><ul><li><strong>概念</strong>：HTTP/HTTPS、TCP/IP、DNS、SMTP。</li><li><strong>应用</strong>：实现网络通信，优化网络性能。</li></ul><h3 id="实践技巧" tabindex="-1">实践技巧 <a class="header-anchor" href="#实践技巧" aria-label="Permalink to “实践技巧”">​</a></h3><h4 id="代码审查和重构" tabindex="-1">代码审查和重构 <a class="header-anchor" href="#代码审查和重构" aria-label="Permalink to “代码审查和重构”">​</a></h4><ul><li><strong>概念</strong>：代码审查、重构技术。</li><li><strong>应用</strong>：提高代码质量，减少技术债务。</li></ul><h4 id="自动化测试" tabindex="-1">自动化测试 <a class="header-anchor" href="#自动化测试" aria-label="Permalink to “自动化测试”">​</a></h4><ul><li><strong>概念</strong>：单元测试、集成测试、端到端测试。</li><li><strong>应用</strong>：确保代码正确性，自动化测试流程。</li></ul><h4 id="版本控制" tabindex="-1">版本控制 <a class="header-anchor" href="#版本控制" aria-label="Permalink to “版本控制”">​</a></h4><ul><li><strong>概念</strong>：Git、SVN等版本控制系统。</li><li><strong>应用</strong>：管理代码版本，协同开发。</li></ul><h3 id="相关问题" tabindex="-1">相关问题 <a class="header-anchor" href="#相关问题" aria-label="Permalink to “相关问题”">​</a></h3><ol><li>如何有效地进行需求分析和系统设计？</li><li>在设计分布式系统时，如何处理数据一致性和系统可用性之间的权衡？</li><li>面对不断变化的技术栈，如何保持代码的可维护性和可扩展性？</li></ol><p>掌握这些基础知识和理论，将有助于你从高层次进行程序和系统设计，确保系统的可靠性、可维护性和性能。</p><h1 id="概念" tabindex="-1">概念 <a class="header-anchor" href="#概念" aria-label="Permalink to “概念”">​</a></h1><h2 id="指针" tabindex="-1">指针 <a class="header-anchor" href="#指针" aria-label="Permalink to “指针”">​</a></h2><blockquote><p>&quot;计算机科学中的任何问题都可以通过增加一个间接层来解决。&quot;</p></blockquote><p>指针是一种数据类型, 指针也是一个实体</p><h3 id="多维视角" tabindex="-1">多维视角 <a class="header-anchor" href="#多维视角" aria-label="Permalink to “多维视角”">​</a></h3><ul><li>从硬件层面看</li><li>从内存模型看</li><li>从程序</li></ul><h3 id="栈指针" tabindex="-1">栈指针 <a class="header-anchor" href="#栈指针" aria-label="Permalink to “栈指针”">​</a></h3><p>也就是栈地址</p><h3 id="帧指针" tabindex="-1">帧指针 <a class="header-anchor" href="#帧指针" aria-label="Permalink to “帧指针”">​</a></h3><h3 id="栈、栈指针、帧指针、栈帧的区别" tabindex="-1">栈、栈指针、帧指针、栈帧的区别 <a class="header-anchor" href="#栈、栈指针、帧指针、栈帧的区别" aria-label="Permalink to “栈、栈指针、帧指针、栈帧的区别”">​</a></h3><p>stack 栈槽</p><p>heap 堆</p><h2 id="栈帧-stack-frame" tabindex="-1">栈帧(stack frame) <a class="header-anchor" href="#栈帧-stack-frame" aria-label="Permalink to “栈帧(stack frame)”">​</a></h2><h1 id="内存布局" tabindex="-1">内存布局 <a class="header-anchor" href="#内存布局" aria-label="Permalink to “内存布局”">​</a></h1><blockquote><p>内存模型, 内存模型</p></blockquote><h2 id="内存布局类型" tabindex="-1">内存布局类型 <a class="header-anchor" href="#内存布局类型" aria-label="Permalink to “内存布局类型”">​</a></h2><ul><li><strong>代码段</strong>：放机器指令</li><li><strong>只读数据段</strong>：放字符串字面量、只读常量等</li><li><strong>已初始化数据段</strong>：放已初始化的全局/静态变量</li><li><strong>未初始化数据段（BSS）</strong>：放未初始化或初始化为 0 的全局/静态变量</li><li><strong>堆</strong>：运行时动态分配, 向上增长(内存地址越来越大)</li><li><strong>栈</strong>：函数调用栈、本地变量等, 向下增长(内存地址越来越小)</li><li>栈与堆: 堆通常在低地址, 栈在高地址</li></ul><h1 id="函数调用" tabindex="-1">函数调用 <a class="header-anchor" href="#函数调用" aria-label="Permalink to “函数调用”">​</a></h1><p>栈, 内存布局</p><h1 id="编程思想" tabindex="-1">编程思想 <a class="header-anchor" href="#编程思想" aria-label="Permalink to “编程思想”">​</a></h1><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to “核心概念”">​</a></h2><ul><li><strong>面向对象编程（Object-Oriented Programming, OOP）</strong>：强调封装、继承和多态性。</li><li><strong>函数式编程（Functional Programming）</strong>：强调纯函数、不可变性和高阶函数。</li><li><strong>响应式编程（Reactive Programming）</strong>：强调数据流和变化传播，适用于异步和事件驱动的应用。</li><li><strong>面向切面编程（Aspect-Oriented Programming, AOP）</strong>：强调分离横切关注点，例如日志记录、安全性等。</li><li><strong>元编程（Metaprogramming）</strong>：编写能操作其他代码的代码，例如装饰器和元类。</li><li><strong>并发编程（Concurrent Programming）</strong>：包括多线程、多进程和异步编程，强调并发执行任</li></ul>',93)])])}const m=r(n,[["render",o]]);export{b as __pageData,m as default};
